import { calculateTax, TaxError } from "./calculateTax";

describe("calculateTax", () => {
  // ── AC1: income below $10,000 (exclusive) → tax = 0 ─────────────────────
  it("AC1: returns 0 for income of $9,999 (just below 10% bracket)", () => {
    expect(calculateTax(9_999)).toBe(0);
  });

  it("AC1: returns 0 for income of $1 (well below bracket)", () => {
    expect(calculateTax(1)).toBe(0);
  });

  it("AC1: returns 0 for income of $9,999.99 (floating-point just below threshold)", () => {
    expect(calculateTax(9_999.99)).toBe(0);
  });

  // ── AC2: income = $10,000 → tax = income * 0.10 ──────────────────────────
  it("AC2: returns income * 0.10 for income of exactly $10,000 (bracket starts inclusive)", () => {
    expect(calculateTax(10_000)).toBe(1_000);
  });

  // ── AC3: income $10,001–$50,000 → tax = income * 0.10 ───────────────────
  it("AC3: returns income * 0.10 for income of $10,001 (just above lower boundary)", () => {
    expect(calculateTax(10_001)).toBeCloseTo(1_000.1, 5);
  });

  it("AC3: returns income * 0.10 for income of $30,000 (mid bracket)", () => {
    expect(calculateTax(30_000)).toBe(3_000);
  });

  // ── AC4: income = $50,000 → tax = income * 0.10 (25% starts at $50,001) ─
  it("AC4: returns income * 0.10 for income of exactly $50,000 (still 10% bracket)", () => {
    expect(calculateTax(50_000)).toBe(5_000);
  });

  // ── AC5: income $50,001–$150,000 → tax = income * 0.25 ──────────────────
  it("AC5: returns income * 0.25 for income of $50,001 (first dollar of 25% bracket)", () => {
    expect(calculateTax(50_001)).toBeCloseTo(12_500.25, 5);
  });

  it("AC5: returns income * 0.25 for income of $100,000 (mid bracket)", () => {
    expect(calculateTax(100_000)).toBe(25_000);
  });

  // ── AC6: income above $150,000 → tax = income * 0.40 ────────────────────
  it("AC6: returns income * 0.40 for income of $150,001 (first dollar of 40% bracket)", () => {
    expect(calculateTax(150_001)).toBeCloseTo(60_000.4, 5);
  });

  it("AC6: returns income * 0.40 for income of $500,000 (well into 40% bracket)", () => {
    expect(calculateTax(500_000)).toBe(200_000);
  });

  // ── AC7: income = $150,000 → tax = income * 0.25 (25% ends inclusive) ───
  it("AC7: returns income * 0.25 for income of exactly $150,000 (25% bracket ends inclusive)", () => {
    expect(calculateTax(150_000)).toBe(37_500);
  });

  // ── AC8: income = 0 or negative → throw TaxError with code INVALID_INCOME
  it("AC8: throws TaxError with code INVALID_INCOME for income of 0", () => {
    expect(() => calculateTax(0)).toThrow(TaxError);
    try {
      calculateTax(0);
    } catch (err) {
      expect((err as TaxError).code).toBe("INVALID_INCOME");
    }
  });

  it("AC8: throws TaxError with code INVALID_INCOME for a negative income", () => {
    expect(() => calculateTax(-1)).toThrow(TaxError);
    try {
      calculateTax(-1);
    } catch (err) {
      expect((err as TaxError).code).toBe("INVALID_INCOME");
    }
  });

  it("AC8: throws TaxError with code INVALID_INCOME for a large negative income", () => {
    expect(() => calculateTax(-999_999)).toThrow(TaxError);
    try {
      calculateTax(-999_999);
    } catch (err) {
      expect((err as TaxError).code).toBe("INVALID_INCOME");
    }
  });
});

